The `debounce` function is a higher-order function that prevents a function from being called too many times in a short period of time by delaying its execution.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      func(...args);
    }, delay);
  };
}

// Example usage:
function logHello(name) {
  console.log(`Hello, ${name}!`);
}

const debouncedLogHello = debounce(logHello, 500);

debouncedLogHello("Alice"); // This will log "Hello, Alice!" after 500ms
debouncedLogHello("Bob");   // This will cancel the previous log and log "Hello, Bob!" after 500ms
```
